insert into exercises (name, primary_muscle_group, secondary_muscle_groups, muscle_groups, category, movement_type, equipment, difficulty_level, is_compound, instructions, common_mistakes, subcategory, coaching_cues, progressions, regressions, tags, contraindications, force_type, plane_of_motion, is_unilateral, sets_default, reps_default, duration_seconds, rest_seconds, is_system) values

('Postnatal Yoga – Restorative Sequence',
 'core', array['hip_flexors','glutes'], array['core'],
 'yoga_pilates', 'flexibility', array['yoga_mat','yoga_blocks'], 'beginner', false,
 'A gentle restorative yoga practice for postnatal recovery. Sequence (20-30 minutes): (1) Child''s pose with wide knees to accommodate postpartum belly — 2 minutes. (2) Cat-cow for spinal mobilisation — 1 minute. (3) Supine knees-to-chest gentle rock — 1 minute. (4) Happy baby pose (supine, holding the feet, gentle hip opening) — 2 minutes. (5) Supported savasana (pillow under knees, supported throughout) — 5 minutes. This sequence reduces cortisol, promotes parasympathetic nervous system recovery, improves pelvic mobility, and supports mental wellbeing. Clear with provider before starting.',
 'Performing yoga styles that are too vigorous (hot yoga, power yoga, or vinyasa flow — not appropriate in the early postnatal period); poses that require strong core (plank variations, boat pose — avoid until core is rehabilitated); rushing through without relaxing into the poses.',
 'postnatal', array['Restorative only: this is NOT a yoga workout — it is rest with movement','Modify everything: pregnancy and postpartum bodies need prop support','Breathe deeply: the breath is the primary tool here','5 minutes savasana: rest is non-negotiable — do not skip it'],
 array['Gentle flow yoga class (8-12 weeks postnatal)','Prenatal/postnatal yoga studio class','Yoga Nidra for deep rest and recovery'],
 array['Guided relaxation lying down only','Breathing and mindfulness practice','Rest in bed or on a mat'],
 array['postnatal','yoga','restorative','mental_wellbeing','gentle','recovery'], array['pelvic_organ_prolapse_symptomatic'],
 'isometric', 'multi', false, 1, null, 1800, null, true),

('Pelvic Organ Prolapse – Safe Exercise Screen',
 'core', array['glutes'], array['core'],
 'rehab', 'other', array['bodyweight'], 'beginner', false,
 'Pelvic organ prolapse (POP) affects approximately 50% of women who have delivered vaginally. Symptoms: sensation of heaviness, dragging, or bulging in the vaginal area; difficulty emptying the bladder or bowel; discomfort during exercise or intercourse. Safe exercise principles with POP: (1) Avoid high-impact activities (running, jumping) until medically assessed. (2) Avoid heavy lifting and breath-holding exercises. (3) Use exhale-on-effort pelvic floor coordination for all exercises. (4) Prioritise Kegels and pelvic floor strengthening. (5) All exercise choices should be symptom-free — if symptoms worsen during exercise, stop and see a pelvic floor physiotherapist.',
 'Ignoring prolapse symptoms and continuing high-impact exercise; high-intensity training without pelvic floor assessment; using waist trainers or abdominal binders without physiotherapy guidance; not seeking medical review of symptoms.',
 'postnatal', array['Symptom-free exercise: if it causes heaviness or pressure — stop','Exhale on effort: every single exercise, every rep','Low impact initially: walking, swimming, cycling are appropriate first steps','Physiotherapy is the gold standard: POP management requires specialist guidance'],
 array['Pelvic floor physiotherapy guided program','Pessary fitting and management guidance','Surgical consultation if conservative management fails'],
 array['Rest and observation','Breathing exercises only','Supine pelvic floor activation'],
 array['postnatal','pelvic_organ_prolapse','safe_exercise','pelvic_floor','management'], array['pelvic_organ_prolapse_stage_3_4_unmanaged'],
 'isometric', 'sagittal', false, 1, null, null, null, true),

('Baby-Inclusive Workout – Pram Walk with Intervals',
 'cardiovascular', array['quadriceps','glutes'], array['cardiovascular','quadriceps'],
 'cardio', 'other', array['pram'], 'beginner', false,
 'The pram (stroller) walk with intervals is a gateway to fitness for new parents who cannot arrange childcare. Start with 20 minutes of brisk walking. Add 1-minute faster walk (conversational effort becomes slightly harder) every 5 minutes. Progress over weeks: add hills, increase duration, and eventually include light jogging intervals. Pram running requires: a running pram (stroller designed for running), the baby at minimum 6 months old, and running clearance from a pelvic floor assessment. The social aspect — joining a pram walking group — improves postnatal mental health significantly.',
 'Using a non-running pram for running intervals (safety risk — not all prams are designed for running); pram running with a baby under 6 months (lack of head/neck control); pushing the pram at arm-width from the body (creates a poor posture — keep the pram close and walk with good posture).',
 'postnatal', array['Running pram for jogging: not all prams are running prams — check the specs','6 months minimum for running prams: head control development','Good posture: upright, not hunched over the pram handle','Join a group: pram walking groups are excellent for postnatal mental health'],
 array['Pram running intervals (6+ months with appropriate pram)','Pram walking hike with hills','Baby-wearing walk (different exercise — weight carried closer to centre of gravity)'],
 array['Short 10-minute walks only','Very slow stroll with rest stops','Seated indoor exercise if outdoor not possible'],
 array['postnatal','baby_inclusive','pram_walk','cardio','mother','mental_health'], array['pelvic_organ_prolapse_symptomatic','return_to_running_not_cleared'],
 'locomotion', 'sagittal', false, 1, null, 1800, null, true),

('Baby-Inclusive – Supine Baby Leg Press',
 'quadriceps', array['glutes'], array['quadriceps','glutes'],
 'strength', 'strength', array['bodyweight'], 'beginner', false,
 'Fun postnatal exercise including the baby. Lie on your back with knees bent, feet lifted. Place the baby tummy-down on your shins (holding the baby securely with your hands). Extend the legs to push the baby upward — airplane! Lower slowly. This is a gentle leg press with light resistance (the baby). Benefits: gentle quadricep and core activation, bonding time, and the joy-factor encourages adherence to postnatal exercise. Appropriate from 8-12 weeks postnatally when core has some rehabilitation. ONLY with a baby who has adequate head control (minimum 4-6 months) and while maintaining full hands-on support.',
 'Using with a newborn without head control (minimum 4-6 months); doing this without hands continuously on the baby; extending the legs fully fast and dropping the baby suddenly; doing this exercise if the mother has diastasis recti without core rehabilitation.',
 'postnatal', array['Hands on baby always: never release','Head control required: minimum 4-6 months old','Slow and controlled: this is not a power movement','Bonding exercise: make it playful and fun — the adherence benefit is enormous'],
 array['Baby overhead press (with full head control, supported)','Baby squat (holding baby in a front-carry position)','Baby-wearing weighted exercises'],
 array['Bodyweight supine leg press (no baby — earlier stage)','Supine glute bridge','Heel slide'],
 array['postnatal','baby_inclusive','bonding','leg_press','fun','postnatal_exercise'], array['diastasis_recti_unrehabilitated','baby_under_4_months'],
 'push', 'sagittal', false, 3, 10, null, 60, true),

('Postnatal Pilates – Core Reconnection',
 'core', array['pelvic_floor','glutes'], array['core'],
 'yoga_pilates', 'other', array['yoga_mat'], 'beginner', false,
 'Clinical postnatal Pilates focuses on deep core reconnection rather than six-pack aesthetics. Key exercises: (1) Imprinting (finding neutral spine on the mat); (2) Breathing with pelvic floor coordination; (3) Leg slides (heel slide equivalent); (4) Bent-knee fallout (single-leg hip external rotation with core brace); (5) Single-leg table top (legs lifted to 90° one at a time with breath management); (6) Gentle bridge. All performed with breathing cues and pelvic floor activation. Appropriate from 6 weeks postnatal (vaginal) or 8-10 weeks (C-section) with clearance.',
 'Performing Pilates 100s, roll-ups, or double-leg stretches too early (these create high intra-abdominal pressure — contraindicated for DR and early postnatal recovery); going to a regular Pilates class not designed for postnatal women.',
 'postnatal', array['Postnatal specific: not a regular Pilates class — it is specialized','Deep before global: transverse abdominis and pelvic floor before rectus abdominis','No coning: watch the midline for any doming on every exercise','6 week minimum: sooner than 6 weeks is too early for most women'],
 array['Full postnatal Pilates program with instructor','Intermediate Pilates return-to-class','Reformer Pilates for postnatal (6+ months)'],
 array['Breathing and pelvic floor coordination only','Physiotherapy-guided core exercises','Rest and recovery (pre-6 weeks)'],
 array['postnatal','pilates','core_reconnection','clinical','pelvic_floor','diastasis'], array['C_section_wound_not_healed'],
 'isometric', 'sagittal', false, 3, 10, null, 45, true);
